create procedure [dbo].[CREATE_CDNRA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.CDNRA','U') IS NOT NULL DROP TABLE CDNRA CREATE TABLE CDNRA ( [GSTIN/UIN] varchar(50), [Original Debit Note Number] varchar(21), [Original Debit Note date] datetime, [Revised Debit Note Number] varchar(21), [Revised Debit Note date] datetime, [Note Type] varchar(1), [Reason For Issuing Note] varchar(15), [Invoice Number] varchar(32),  [Invoice date] datetime, [Total Invoice Value] decimal, [IGST Rate] decimal, [IGST Amount] decimal, [CGST Rate] decimal, [CGST Amount] decimal, [SGST Rate] decimal, [SGST Amount] decimal, [CESS Rate] decimal, [CESS Amount] decimal, [E-Commerce GSTIN] varchar(1) ) Set @Tablename='CDNRA' Select @Tablename 